   203→        UpdateChecker checker(this);
   204→
   205→        // forwards notifications only the first time
   206→        if (calculated_ || alwaysForward_) {
   207→            // set to false early
   208→            // 1) to prevent infinite recursion
   209→            // 2) otherways non-lazy observers would be served obsolete
   210→            //    data because of calculated_ being still true
   211→            calculated_ = false;
   212→            // observers don't expect notifications from frozen objects
   213→            if (!frozen_)
   214→                notifyObservers();
   215→                // exiting notifyObservers() calculated_ could be
   216→                // already true because of non-lazy observers
   217→        }
   218→    }
   219→
   220→    inline void LazyObject::recalculate() {
   221→        bool wasFrozen = frozen_;
   222→        calculated_ = frozen_ = false;
   223→        try {
   224→            calculate();
   225→        } catch (...) {
   226→            frozen_ = wasFrozen;
   227→            notifyObservers();
   228→            throw;
   229→        }
   230→        frozen_ = wasFrozen;
   231→        notifyObservers();
   232→    }
   233→
   234→    inline void LazyObject::freeze() {
   235→        frozen_ = true;
   236→    }
   237→
   238→    inline void LazyObject::unfreeze() {
   239→        // send notifications, just in case we lost any,
   240→        // but only once, i.e. if it was frozen
   241→        if (frozen_) {
   242→            frozen_ = false;
   243→            notifyObservers();
   244→        }
   245→    }
   246→
   247→    inline void LazyObject::forwardFirstNotificationOnly() {
   248→        alwaysForward_ = false;
   249→    }
   250→
   251→    inline void LazyObject::alwaysForwardNotifications() {
   252→        alwaysForward_ = true;
   253→    }
   254→
   255→    inline void LazyObject::calculate() const {
   256→        if (!calculated_ && !frozen_) {
   257→            calculated_ = true;   // prevent infinite recursion in
   258→                                  // case of bootstrapping
   259→            try {
   260→                performCalculations();
   261→            } catch (...) {
   262→                calculated_ = false;
   263→                throw;
   264→            }
   265→        }
   266→    }
   267→
   268→    inline bool LazyObject::isCalculated() const {
   269→        return calculated_;
   270→    }
   271→
   272→    inline void LazyObject::setCalculated(const bool c) const {
   273→        calculated_ = c;
   274→    }
   275→}
