   121→        MakeMCBarrierEngine& withStepsPerYear(Size steps);
   122→        MakeMCBarrierEngine& withBrownianBridge(bool b = true);
   123→        MakeMCBarrierEngine& withAntitheticVariate(bool b = true);
   124→        MakeMCBarrierEngine& withSamples(Size samples);
   125→        MakeMCBarrierEngine& withAbsoluteTolerance(Real tolerance);
   126→        MakeMCBarrierEngine& withMaxSamples(Size samples);
   127→        MakeMCBarrierEngine& withBias(bool b = true);
   128→        MakeMCBarrierEngine& withSeed(BigNatural seed);
   129→        // conversion to pricing engine
   130→        operator ext::shared_ptr<PricingEngine>() const;
