   132→        ext::shared_ptr<GeneralizedBlackScholesProcess> process_;
   133→        bool brownianBridge_ = false, antithetic_ = false, biased_ = false;
   134→        Size steps_, stepsPerYear_, samples_, maxSamples_;
   135→        Real tolerance_;
   136→        BigNatural seed_ = 0;
   137→    };
