   294→    inline MakeMCBarrierEngine<RNG,S>&
   295→    MakeMCBarrierEngine<RNG,S>::withBrownianBridge(bool brownianBridge) {
   296→        brownianBridge_ = brownianBridge;
   297→        return *this;
   298→    }
   299→
   300→    template <class RNG, class S>
   301→    inline MakeMCBarrierEngine<RNG,S>&
   302→    MakeMCBarrierEngine<RNG,S>::withAntitheticVariate(bool b) {
   303→        antithetic_ = b;
   304→        return *this;
   305→    }
