   328→    template <class RNG, class S>
   329→    inline MakeMCBarrierEngine<RNG,S>&
   330→    MakeMCBarrierEngine<RNG,S>::withMaxSamples(Size samples) {
   331→        maxSamples_ = samples;
   332→        return *this;
   333→    }
