   335→    template <class RNG, class S>
   336→    inline MakeMCBarrierEngine<RNG,S>&
   337→    MakeMCBarrierEngine<RNG,S>::withBias(bool biased) {
   338→        biased_ = biased;
   339→        return *this;
   340→    }
